"""FastAPI Web 应用"""

from fastapi import FastAPI


def create_app() -> FastAPI:
    """创建 FastAPI 应用"""
    app = FastAPI(
        title="OpenMercury",
        description="AI 驱动的自改进软件开发平台",
        version="0.1.0",
    )

    @app.get("/")
    async def root():
        return {"message": "OpenMercury API", "version": "0.1.0"}

    @app.get("/health")
    async def health():
        return {"status": "ok"}

    @app.post("/chat")
    async def chat(message: str):
        # TODO: 集成 Agent 处理消息
        return {"response": "Chat endpoint - coming soon"}

    return app

"""Agent 核心循环集成测试"""

import pytest
from openmercury.core.config import OpenMercuryConfig, ModelConfig
from openmercury.tools.registry import ToolRegistry
from openmercury.tools.base import BaseTool


class MockTool(BaseTool):
    """模拟工具用于测试"""
    name = "echo"
    description = "回显参数"
    parameters = {
        "type": "object",
        "properties": {
            "message": {"type": "string", "description": "要回显的消息"},
        },
        "required": ["message"],
    }

    async def execute(self, message: str, **kwargs):
        return {"echo": message}


class TestAgentConfig:
    def test_default_config(self):
        cfg = OpenMercuryConfig()
        assert cfg.model.provider == "openai"
        assert cfg.model.model == "gpt-4"

    def test_config_with_model(self):
        cfg = OpenMercuryConfig()
        cfg.model.model = "claude-3"
        cfg.model.provider = "anthropic"
        assert cfg.model.model == "claude-3"


class TestToolRegistry:
    def test_register_and_execute(self):
        registry = ToolRegistry()
        registry.register(MockTool())

        import asyncio
        result = asyncio.get_event_loop().run_until_complete(
            registry.execute("echo", message="hello")
        )
        assert result["echo"] == "hello"

    def test_tool_not_found(self):
        registry = ToolRegistry()

        import asyncio
        result = asyncio.get_event_loop().run_until_complete(
            registry.execute("nonexistent")
        )
        assert "error" in result

"""通用辅助函数"""

import os
import re
from pathlib import Path


def expand_path(path: str) -> Path:
    """展开路径中的 ~ 和环境变量"""
    return Path(os.path.expandvars(os.path.expanduser(path)))


def truncate(text: str, max_length: int = 1000, suffix: str = "...") -> str:
    """截断文本"""
    if len(text) <= max_length:
        return text
    return text[: max_length - len(suffix)] + suffix


def extract_urls(text: str) -> list[str]:
    """提取文本中的 URL"""
    url_pattern = r"https?://[^\s<>\"]+|www\.[^\s<>\"]+"
    return re.findall(url_pattern, text)


def slugify(text: str) -> str:
    """将文本转换为 slug 格式"""
    text = text.lower().strip()
    text = re.sub(r"[^\w\s-]", "", text)
    text = re.sub(r"[\s_-]+", "-", text)
    return text.strip("-")


def format_bytes(bytes: int) -> str:
    """格式化字节数为可读格式"""
    for unit in ["B", "KB", "MB", "GB"]:
        if bytes < 1024:
            return f"{bytes:.1f} {unit}"
        bytes /= 1024
    return f"{bytes:.1f} TB"

"""工具基类"""

from abc import ABC, abstractmethod
from typing import Any


class BaseTool(ABC):
    """所有工具的基类"""

    name: str = ""
    description: str = ""
    parameters: dict = {}

    @property
    def definition(self) -> dict:
        """工具定义（用于 LLM function calling）"""
        return {
            "type": "function",
            "function": {
                "name": self.name,
                "description": self.description,
                "parameters": self.parameters,
            },
        }

    @abstractmethod
    async def execute(self, **kwargs) -> Any:
        """执行工具"""
        pass

    def validate(self, **kwargs) -> bool:
        """验证参数"""
        required = self.parameters.get("required", [])
        return all(key in kwargs for key in required)

