"""沙箱隔离机制"""

import os
import tempfile
from pathlib import Path


class SandboxIsolation:
    """提供执行隔离环境"""

    def __init__(self, work_dir: str = None):
        self.work_dir = work_dir or tempfile.mkdtemp(prefix="openmercury_")
        self.allowed_dirs: list[str] = []

    def allow_directory(self, path: str, read_only: bool = False):
        """允许访问指定目录"""
        self.allowed_dirs.append({"path": path, "read_only": read_only})

    def is_path_allowed(self, path: str, write: bool = False) -> bool:
        """检查路径是否允许访问"""
        target = Path(path).resolve()

        for allowed in self.allowed_dirs:
            allowed_path = Path(allowed["path"]).resolve()
            if target == allowed_path or target.is_relative_to(allowed_path):
                if write and allowed["read_only"]:
                    return False
                return True

        return False

    def cleanup(self):
        """清理临时工作目录"""
        import shutil
        if self.work_dir.startswith("/tmp"):
            shutil.rmtree(self.work_dir, ignore_errors=True)

"""权限控制"""

import fnmatch
from typing import Optional


class PermissionManager:
    """管理工具与命令的访问权限"""

    def __init__(self, mode: str = "ask"):
        """
        mode: "allow" | "ask" | "deny"
        """
        self.mode = mode
        self._rules: dict[str, dict] = {}

    def set_mode(self, mode: str):
        """设置默认权限模式"""
        if mode not in ("allow", "ask", "deny"):
            raise ValueError(f"Invalid mode: {mode}")
        self.mode = mode

    def add_rule(self, tool: str, pattern: str, action: str):
        """添加权限规则"""
        if tool not in self._rules:
            self._rules[tool] = {}
        self._rules[tool][pattern] = action

    def check(self, tool: str, command: str = None) -> str:
        """检查权限，返回 allow/ask/deny"""
        tool_rules = self._rules.get(tool, {})

        # 最后匹配的规则生效
        for pattern, action in tool_rules.items():
            if command is None or fnmatch.fnmatch(command, pattern):
                return action

        return self.mode

    def is_allowed(self, tool: str, command: str = None) -> bool:
        """检查是否允许执行"""
        return self.check(tool, command) == "allow"

    def needs_approval(self, tool: str, command: str = None) -> bool:
        """检查是否需要用户确认"""
        return self.check(tool, command) == "ask"

"""安全检查"""

import re


class SecurityChecker:
    """检查命令与内容的安全性"""

    DANGEROUS_PATTERNS = [
        r"rm\s+-rf\s+/",
        r"mkfs",
        r"dd\s+if=",
        r">\s*/dev/sd",
        r"chmod\s+777\s+/",
        r"wget.*\|\s*bash",
        r"curl.*\|\s*sh",
    ]

    @classmethod
    def check_command(cls, command: str) -> tuple[bool, str]:
        """检查命令是否危险"""
        for pattern in cls.DANGEROUS_PATTERNS:
            if re.search(pattern, command, re.IGNORECASE):
                return False, f"Dangerous pattern detected: {pattern}"
        return True, ""

    @classmethod
    def check_file_path(cls, path: str) -> tuple[bool, str]:
        """检查文件路径是否安全"""
        if ".." in path:
            return False, "Path traversal detected"
        if path.startswith("/proc") or path.startswith("/sys"):
            return False, "Access to system paths not allowed"
        return True, ""

"""审计日志"""

import json
import time
from pathlib import Path


class AuditLogger:
    """记录安全与操作审计日志"""

    def __init__(self, log_path: str = None):
        self.log_path = Path(log_path or "~/.openmercury/audit.log").expanduser()
        self.log_path.parent.mkdir(parents=True, exist_ok=True)

    def log(self, action: str, user: str, details: dict = None):
        """记录审计事件"""
        entry = {
            "timestamp": time.time(),
            "action": action,
            "user": user,
            "details": details or {},
        }

        with open(self.log_path, "a") as f:
            f.write(json.dumps(entry) + "\n")

    def read(self, limit: int = 100) -> list[dict]:
        """读取最近的审计日志"""
        if not self.log_path.exists():
            return []

        entries = []
        with open(self.log_path) as f:
            for line in f:
                line = line.strip()
                if line:
                    entries.append(json.loads(line))

        return entries[-limit:]

"""指标收集"""

import time
from collections import defaultdict


class MetricsCollector:
    """收集与报告系统指标"""

    def __init__(self):
        self._counters: dict[str, int] = defaultdict(int)
        self._timings: dict[str, list[float]] = defaultdict(list)
        self._events: list[dict] = []

    def increment(self, name: str, value: int = 1):
        """增加计数器"""
        self._counters[name] += value

    def record_timing(self, name: str, duration: float):
        """记录耗时"""
        self._timings[name].append(duration)

    def record_event(self, event_type: str, **kwargs):
        """记录事件"""
        self._events.append({
            "type": event_type,
            "timestamp": time.time(),
            **kwargs,
        })

    def get_counter(self, name: str) -> int:
        """获取计数器值"""
        return self._counters.get(name, 0)

    def get_avg_timing(self, name: str) -> float:
        """获取平均耗时"""
        timings = self._timings.get(name, [])
        return sum(timings) / len(timings) if timings else 0.0

    def get_events(self, event_type: str = None, limit: int = 100) -> list[dict]:
        """获取事件列表"""
        events = self._events
        if event_type:
            events = [e for e in events if e["type"] == event_type]
        return events[-limit:]

    def get_summary(self) -> dict:
        """获取指标摘要"""
        return {
            "counters": dict(self._counters),
            "avg_timings": {
                name: sum(vals) / len(vals)
                for name, vals in self._timings.items()
                if vals
            },
            "total_events": len(self._events),
        }

class Tracer:
